import{_ as o,E as r,o as l,c as n,j as a,a as e,I as i,aj as s}from"./chunks/framework.Bljw9wMQ.js";const N=JSON.parse('{"title":"开发计划","description":"","frontmatter":{"title":"开发计划"},"headers":[],"relativePath":"plan.md","filePath":"plan.md","lastUpdated":1773994533000}'),d={name:"plan.md"},h=a("h1",{id:"开发计划",tabindex:"-1"},[e("开发计划 "),a("a",{class:"header-anchor",href:"#开发计划","aria-label":'Permalink to "开发计划"'},"​")],-1),c=a("p",null,"ZXMange 的目标是成为开发者桌面上最得心应手的全能工具箱。我们不仅仅满足于基础的项目管理，更希望通过深入集成开发工作流，提升每一位开发者的效率。",-1),g=a("p",null,"以下是我们的长期规划路线图，具体发布时间可能会根据开发进度进行调整。",-1),u={id:"🚀-近期计划-v1-1-x",tabindex:"-1"},p=a("a",{class:"header-anchor",href:"#🚀-近期计划-v1-1-x","aria-label":'Permalink to "🚀 近期计划 (v1.1.x) <Badge type="tip" text="开发中" />"'},"​",-1),_=s('<p>我们正在努力完善核心功能的深度体验。</p><h3 id="内置终端集成" tabindex="-1">内置终端集成 <a class="header-anchor" href="#内置终端集成" aria-label="Permalink to &quot;内置终端集成&quot;">​</a></h3><ul><li><strong>功能描述</strong>：无需切换到外部 CMD 或 Terminal，在 ZXMange 内部直接打开集成终端。</li><li><strong>价值</strong>：实现“一个窗口搞定所有操作”，支持执行 <code>npm install</code>、<code>git command</code> 等任意指令。</li><li><strong>进度</strong>：底层架构设计中...</li></ul><h3 id="环境管理增强" tabindex="-1">环境管理增强 <a class="header-anchor" href="#环境管理增强" aria-label="Permalink to &quot;环境管理增强&quot;">​</a></h3><ul><li><strong>Node 版本切换</strong>：可视化切换本地 Node 版本（需配合 nvm）。</li><li><strong>依赖分析</strong>：可视化查看 <code>package.json</code> 依赖树，检测过期或存在安全风险的依赖包。</li></ul><h2 id="🌟-中期规划-v1-2-x-v1-6-x" tabindex="-1">🌟 中期规划 (v1.2.x - v1.6.x) <a class="header-anchor" href="#🌟-中期规划-v1-2-x-v1-6-x" aria-label="Permalink to &quot;🌟 中期规划 (v1.2.x - v1.6.x)&quot;">​</a></h2><p>探索更多项目类型的深度支持与团队协作功能。</p><h3 id="小程序开发深度支持" tabindex="-1">小程序开发深度支持 <a class="header-anchor" href="#小程序开发深度支持" aria-label="Permalink to &quot;小程序开发深度支持&quot;">​</a></h3><ul><li><strong>功能描述</strong>：针对微信小程序项目，集成预览二维码生成、上传代码至微信后台等功能。</li><li><strong>扩展</strong>：支持 Uni-app 多端编译预览面板。</li></ul><h3 id="数据库管理模块" tabindex="-1">数据库管理模块 <a class="header-anchor" href="#数据库管理模块" aria-label="Permalink to &quot;数据库管理模块&quot;">​</a></h3><ul><li><strong>功能描述</strong>：支持连接 MySQL、MongoDB、Redis 等常用数据库。</li><li><strong>价值</strong>：在管理代码的同时，直接查看和修改数据，实现真正的全栈开发闭环。</li></ul><h3 id="多项目管理视图" tabindex="-1">多项目管理视图 <a class="header-anchor" href="#多项目管理视图" aria-label="Permalink to &quot;多项目管理视图&quot;">​</a></h3><ul><li><strong>功能描述</strong>：支持看板视图，通过拖拽卡片来管理多个项目的进度状态。</li><li><strong>笔记云同步</strong>：提供可选的云端服务，实现项目笔记在多台设备间同步。</li></ul><h2 id="🏗️-远期愿景-v2-0-0" tabindex="-1">🏗️ 远期愿景 (v2.0.0+) <a class="header-anchor" href="#🏗️-远期愿景-v2-0-0" aria-label="Permalink to &quot;🏗️ 远期愿景 (v2.0.0+)&quot;">​</a></h2><p>构建 ZXMange 插件生态，由社区驱动无限可能。</p><h3 id="插件系统" tabindex="-1">插件系统 <a class="header-anchor" href="#插件系统" aria-label="Permalink to &quot;插件系统&quot;">​</a></h3><ul><li><strong>功能描述</strong>：开放插件 API，允许第三方开发者编写插件扩展软件功能。</li><li><strong>场景</strong>：例如自动生成 CRUD 代码插件、UI 设计稿转代码插件等。</li><li><strong>自定义主题</strong>：支持用户自定义软件界面的颜色主题和布局。</li></ul><h3 id="团队协作版" tabindex="-1">团队协作版 <a class="header-anchor" href="#团队协作版" aria-label="Permalink to &quot;团队协作版&quot;">​</a></h3><ul><li><strong>功能描述</strong>：支持团队创建，共享项目配置、API 文档和部署流程。</li><li><strong>远程开发</strong>：探索 SSH 远程连接服务器项目进行管理的可能性。</li></ul><h2 id="💬-参与讨论" tabindex="-1">💬 参与讨论 <a class="header-anchor" href="#💬-参与讨论" aria-label="Permalink to &quot;💬 参与讨论&quot;">​</a></h2><p>ZXMange 的成长离不开你的建议。如果你对上述计划有任何想法，或者有急需的功能需求，欢迎通过以下方式告诉我们：</p><ul><li><strong>GitHub Issues</strong>: <a href="https://github.com/your-repo/zxmanage/issues" target="_blank" rel="noreferrer">提交功能建议</a></li><li><strong>官方交流群</strong>: 扫描首页二维码加入开发者交流群</li></ul><p>每一个 <code>Feature Request</code> 都会被认真考虑！</p>',23);function x(m,b,f,q,v,P){const t=r("Badge");return l(),n("div",null,[h,c,g,a("h2",u,[e("🚀 近期计划 (v1.1.x) "),i(t,{type:"tip",text:"开发中"}),e(),p]),_])}const S=o(d,[["render",x]]);export{N as __pageData,S as default};
